1	interface CustomerContext {
2	  yearsWithMHPCO: number;
3	  previousQuotes: number;
4	}
5	
6	interface Item {
7	  type: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	}
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const PROCESSING_FEE = 5;
22	
23	const COMPONENT_TYPES = ["rune", "moonstone"];
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	
27	function countByType(items: Item[]): Record<string, number> {
28	  const counts: Record<string, number> = {};
29	  for (const item of items) {
30	    counts[item.type] = (counts[item.type] ?? 0) + 1;
31	  }
32	  return counts;
33	}
34	
35	function basePremiumForType(type: string): number {
36	  return BASE_PREMIUM[type] ?? 0;
37	}
38	
39	function cursedSurchargeFor(item: Item): number {
40	  return item.cursed ? basePremiumForType(item.type) * 0.5 : 0;
41	}
42	
43	function highEnchantmentSurchargeFor(item: Item): number {
44	  return (item.enchantment ?? 0) >= 5 ? basePremiumForType(item.type) * 0.3 : 0;
45	}
46	
47	function premiumForGroup(type: string, count: number): number {
48	  if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
49	    return BLOCK_PREMIUM;
50	  }
51	  return count * basePremiumForType(type);
52	}
53	
54	export function quote(items: Item[], customer: CustomerContext): number {
55	  const counts = countByType(items);
56	
57	  const basePremium = Object.entries(counts)
58	    .reduce((sum, [type, count]) => sum + premiumForGroup(type, count), 0);
59	
60	  const cursedSurcharge = items.reduce((sum, item) =>
61	    sum + cursedSurchargeFor(item), 0);
62	
63	  const enchantmentSurcharge = items.reduce((sum, item) =>
64	    sum + highEnchantmentSurchargeFor(item), 0);
65	
66	  return basePremium + cursedSurcharge + enchantmentSurcharge + PROCESSING_FEE;
67	}
68	
